func compress(chars []byte) int {
	s := ""
	count := 0
	i := 0
	for i < len(chars) {
		if i != 0 && chars[i] == chars[i-1] {
			count++
		} else {
			if count > 1 { // add the count to the string s if it is > 1
				s += strconv.Itoa(count)
			}
			s += string(chars[i]) // add the new character as it is not maching with i-1
			count = 1             // reset the count to 1
		}
		i++
	}

	if i == len(chars) && count > 1 { // add the count for the last repeted char like abbb
		s += strconv.Itoa(count)
	}

	// filling the input chars from s
	for i, v := range s {
		chars[i] = byte(v)
	}
	return len(s)
}

